// src/pages/Register.jsx
import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import "./Register.css";

export default function Register() {
  const [role, setRole] = useState("");
  const [secretKey, setSecretKey] = useState("");
  const navigate = useNavigate();

  const handleRegister = (e) => {
    e.preventDefault();

    const users = JSON.parse(localStorage.getItem("users")) || [];
    const form = e.target;
    const name = form.name.value.trim();
    const email = form.email?.value?.trim();
    const roll = form.rollno?.value?.trim();
    const password = form.password.value.trim();
    const selectedRole = form.role.value;

    // Secret key check
    if (selectedRole === "admin" && secretKey !== "ADMIN123") {
      alert("Invalid Admin Secret Key!");
      return;
    }
    if (selectedRole === "hr" && secretKey !== "HR123") {
      alert("Invalid HR Secret Key!");
      return;
    }

    const newUser = {
      name,
      password,
      role: selectedRole,
      ...(selectedRole === "student" ? { roll } : { email }),
    };

    users.push(newUser);
    localStorage.setItem("users", JSON.stringify(users));
    alert("Registration Successful!");
    navigate("/login");
  };

  return (
    <div className="register-layout">
      <div className="register-left">
        <h1>🎓 Campus Connect</h1>
        <h2>Register & Explore!</h2>
        <img
          src="https://img.freepik.com/premium-vector/college-registration-concept-illustration_701961-1017.jpg"
          alt="Register"
        />
      </div>

      <div className="register-right">
        <div className="form-container">
          <div className="tabs">
            <Link to="/login" className="tab">Login</Link>
            <Link to="/register" className="tab active">Signup</Link>
          </div>

          <form onSubmit={handleRegister}>
            <label>Name</label>
            <input name="name" required placeholder="Enter your full name" />

            <label>Role</label>
            <select
              name="role"
              required
              value={role}
              onChange={(e) => setRole(e.target.value)}
            >
              <option value="">-- Select Role --</option>
              <option value="student">Student</option>
              <option value="admin">Admin</option>
              <option value="hr">HR</option>
            </select>

            {role === "student" && (
              <>
                <label>University Roll Number</label>
                <input name="rollno" required placeholder="Roll No" />
              </>
            )}

            {role !== "student" && role && (
              <>
                <label>Email</label>
                <input name="email" type="email" required placeholder="Email" />
              </>
            )}

            {(role === "admin" || role === "hr") && (
              <>
                <label>Secret Key</label>
                <input
                  type="password"
                  placeholder="Secret Key"
                  value={secretKey}
                  onChange={(e) => setSecretKey(e.target.value)}
                  required
                />
              </>
            )}

            <label>Password</label>
            <input name="password" type="password" required placeholder="Password" />

            <button type="submit">Register</button>
          </form>

          <p className="signup-cta">
            Already registered?{" "}
            <Link to="/login">
              <strong>Login here</strong>
            </Link>
          </p>

          <Link to="/" className="back-home-link">← Back to Home</Link>
        </div>
      </div>
    </div>
  );
}
